import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Dashboard.css';

function Dashboard() {
  const navigate = useNavigate();
  const [userName, setUserName] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    // Fetch user data
    fetch(`http://localhost:5000/api/user/${user_id}`)
      .then(response => response.json())
      .then(data => {
        if (data.name) {
          setUserName(data.name);
        }
      })
      .catch(error => {
        console.error('Error fetching user data:', error);
      });
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className="dashboard-container">
      <div className="top-bar">
        <div className="header-content">
          <h1>Asthma Monitoring</h1>
          <div className="welcome-section">
            <span>Welcome, {userName}</span>
          </div>
        </div>
        <div className="nav-buttons">
          <button className="profile-button" onClick={() => navigate('/profile')}>
            Profile
          </button>
          <button className="logout-button" onClick={handleLogout}>
            Logout
          </button>
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <button className="sidebar-toggle" onClick={toggleSidebar}>
          {isSidebarOpen ? '×' : '☰'}
        </button>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/recording')}>Recording indicators</button>
          <button onClick={() => navigate('/forecast')}>Exacerbation forecast</button>
          <button onClick={() => navigate('/graphs')}>Graphs of changes in indicators</button>
          <button onClick={() => navigate('/medication')}>Medication diary</button>
        </nav>
      </div>

      <div className="main-content">
        <h2>Dashboard</h2>
        <p>Select an option from the sidebar to get started.</p>
      </div>
    </div>
  );
}

export default Dashboard;
